class AuthManager(private val context: Context) {

    private val sharedPreferences: SharedPreferences = context.getSharedPreferences("auth_prefs", Context.MODE_PRIVATE)
    
    companion object {
        private const val KEY_AUTH_TOKEN = "auth_token"
        private const val KEY_USER_ID = "user_id"
    }

    fun authenticate(username: String, password: String): Boolean {
        // Simulate authentication logic
        if (username == "user" && password == "password") {
            saveAuthData("sample_auth_token", "user_id_123")
            return true
        }
        return false
    }

    private fun saveAuthData(authToken: String, userId: String) {
        sharedPreferences.edit().apply {
            putString(KEY_AUTH_TOKEN, authToken)
            putString(KEY_USER_ID, userId)
            apply()
        }
    }

    fun isUserLoggedIn(): Boolean {
        return sharedPreferences.contains(KEY_AUTH_TOKEN) && sharedPreferences.contains(KEY_USER_ID)
    }

    fun getAuthToken(): String? {
        return sharedPreferences.getString(KEY_AUTH_TOKEN, null)
    }

    fun getUserId(): String? {
        return sharedPreferences.getString(KEY_USER_ID, null)
    }

    fun logout() {
        sharedPreferences.edit().clear().apply()
    }
